// 1. O(3n + 100) = O(n)
//    Drop constant 3 and constant 100
//    Java: for (int i = 0; i < 3*n; i++) { doConstantWork(); }

// 2. O(n² + 50n + 1000) = O(n²)
//    n² dominates 50n (at n=100: n²=10000 vs 50n=5000, at n=1000: n²=1M vs 50n=50K)
//    Drop lower-order terms: 50n and constant 1000
//    Java: for (int i=0;i<n;i++) for (int j=0;j<n;j++) { work(); }

// 3. O(n³ + n² + n) = O(n³)
//    n³ dominates all lower-degree polynomials
//    Java: 3 nested loops: for i...for j...for k...{ work(); }

// 4. O(2ⁿ + n¹⁰⁰) = O(2ⁿ)
//    Exponential always dominates polynomial (even n^100)
//    At n=1000: 2^1000 >> 1000^100 (astronomically larger)
//    Java: recursive subset generation

// 5. O(n log n + n) = O(n log n)
//    n log n dominates n (n log n / n = log n → infinity)
//    Java: Collections.sort(list); then one more loop

public class BigOSimplification {
    public static void main(String[] args) {
        System.out.println("O(3n+100) = O(n)");
        System.out.println("O(n²+50n+1000) = O(n²)");
        System.out.println("O(n³+n²+n) = O(n³)");
        System.out.println("O(2ⁿ+n¹⁰⁰) = O(2ⁿ)");
        System.out.println("O(n log n + n) = O(n log n)");
    }
}

