import java.util.*;
public class TwoSumComparison {

    // Solution A: O(n²) — brute force, check every pair
    static boolean solutionA(int[] nums, int target) {
        for (int i = 0; i < nums.length; i++)
            for (int j = i + 1; j < nums.length; j++)
                if (nums[i] + nums[j] == target) return true;
        return false;
    }

    // Solution B: O(n) — HashSet, for each num check if complement exists
    static boolean solutionB(int[] nums, int target) {
        Set<Integer> seen = new HashSet<>();
        for (int num : nums) {
            if (seen.contains(target - num)) return true;
            seen.add(num);
        }
        return false;
    }

    public static void main(String[] args) {
        int n = 100_000;
        int[] trades = new int[n];
        Random rand = new Random(42);
        for (int i = 0; i < n; i++) trades[i] = rand.nextInt(200_000) - 100_000;
        int target = 0;

        long startA = System.currentTimeMillis();
        boolean resultA = solutionA(trades, target);
        long timeA = System.currentTimeMillis() - startA;

        long startB = System.currentTimeMillis();
        boolean resultB = solutionB(trades, target);
        long timeB = System.currentTimeMillis() - startB;

        System.out.println("Solution A (O(n²)): " + resultA + " in " + timeA + "ms");
        System.out.println("Solution B (O(n)):  " + resultB + " in " + timeB + "ms");
        System.out.println("Both correct: " + (resultA == resultB));
        System.out.println("Theoretical speedup: n/2 ≈ " + (n/2) + "x faster");
        System.out.println("Complexity: A=O(n²), B=O(n) — classic interview optimization");
    }
}

