import java.util.*;
public class DuplicateFinder {

    // O(n²): for each element, scan the rest
    static List<Integer> findDupsQuadratic(int[] trades) {
        List<Integer> dups = new ArrayList<>();
        for (int i = 0; i < trades.length; i++)
            for (int j = i + 1; j < trades.length; j++)
                if (trades[i] == trades[j] && !dups.contains(trades[i]))
                    dups.add(trades[i]);
        return dups;
    }

    // O(n): HashSet tracks seen elements
    static List<Integer> findDupsLinear(int[] trades) {
        Set<Integer> seen = new HashSet<>();
        Set<Integer> dups = new LinkedHashSet<>();
        for (int t : trades) {
            if (!seen.add(t)) dups.add(t); // add returns false if already present
        }
        return new ArrayList<>(dups);
    }

    public static void main(String[] args) {
        int[] sizes = {1_000, 10_000, 50_000};
        Random rand = new Random(42);

        System.out.printf("%-10s %-15s %-15s %-12s%n", "n", "O(n²) ms", "O(n) ms", "Speedup");
        System.out.println("-".repeat(52));

        for (int n : sizes) {
            int[] trades = new int[n];
            for (int i = 0; i < n; i++) trades[i] = rand.nextInt(n / 2); // 50% chance of dup

            long s1 = System.currentTimeMillis();
            findDupsQuadratic(trades);
            long t1 = System.currentTimeMillis() - s1;

            long s2 = System.currentTimeMillis();
            findDupsLinear(trades);
            long t2 = System.currentTimeMillis() - s2;

            String speedup = t2 > 0 ? String.valueOf(t1/t2) + "x" : ">1000x";
            System.out.printf("%-10d %-15d %-15d %-12s%n", n, t1, Math.max(t2, 0), speedup);
        }
        System.out.println();
        System.out.println("Insight: speedup grows with n — O(n) scales, O(n²) doesn't");
    }
}

