import java.util.*;
public class MostFrequentTrade {

    // O(n) time, O(n) space
    public static String findMostFrequent(String[] trades) {
        if (trades == null || trades.length == 0) return null;

        // Step 1: count frequencies — O(n)
        Map<String, Integer> freq = new HashMap<>();
        for (String trade : trades) {
            freq.put(trade, freq.getOrDefault(trade, 0) + 1);
        }

        // Step 2: find max — O(n) over the map entries
        String maxTrade = null;
        int maxCount = 0;
        for (Map.Entry<String, Integer> entry : freq.entrySet()) {
            if (entry.getValue() > maxCount) {
                maxCount = entry.getValue();
                maxTrade = entry.getKey();
            }
        }
        return maxTrade;
        // Total: O(n) + O(n) = O(n) ✓
    }

    public static void main(String[] args) {
        // Small test:
        String[] small = {"RELIANCE","TCS","RELIANCE","INFY","TCS","RELIANCE"};
        System.out.println("Most frequent: " + findMostFrequent(small));
        System.out.println("Expected: RELIANCE");

        // Benchmark n=1,000,000:
        int n = 1_000_000;
        String[] stocks = {"RELIANCE","TCS","INFY","HDFCBANK","WIPRO"};
        String[] bigTrades = new String[n];
        Random rand = new Random(42);
        for (int i = 0; i < n; i++) bigTrades[i] = stocks[rand.nextInt(stocks.length)];

        long start = System.currentTimeMillis();
        String result = findMostFrequent(bigTrades);
        long time = System.currentTimeMillis() - start;

        System.out.println("n=1M most frequent: " + result + " in " + time + "ms");
        System.out.println("Complexity: O(n) — two linear passes");
        System.out.println(time < 1000 ? "PASS: under 1 second" : "SLOW: check implementation");
    }
}

