public class CountInversions {

    // O(n²): check every pair
    static long bruteForce(int[] prices) {
        long count = 0;
        for (int i = 0; i < prices.length; i++)
            for (int j = i + 1; j < prices.length; j++)
                if (prices[i] > prices[j]) count++;
        return count;
    }

    // O(n log n): modified merge sort
    // Key insight: during merge, when right element < left element,
    // ALL remaining left elements form inversions with that right element
    static long mergeCount(int[] arr, int[] temp, int l, int r) {
        if (l >= r) return 0;
        int mid = l + (r - l) / 2;
        long count = mergeCount(arr, temp, l, mid) + mergeCount(arr, temp, mid+1, r);
        int i = l, j = mid+1, k = l;
        while (i <= mid && j <= r) {
            if (arr[i] <= arr[j]) {
                temp[k++] = arr[i++];
            } else {
                // arr[i] > arr[j]: all arr[i..mid] are > arr[j] (sorted)
                count += (mid - i + 1); // ALL remaining left elements form inversions
                temp[k++] = arr[j++];
            }
        }
        while (i <= mid) temp[k++] = arr[i++];
        while (j <= r) temp[k++] = arr[j++];
        for (int x = l; x <= r; x++) arr[x] = temp[x];
        return count;
    }

    static long mergeSort(int[] prices) {
        return mergeCount(prices.clone(), new int[prices.length], 0, prices.length - 1);
    }

    public static void main(String[] args) {
        int[] prices = {3, 1, 2, 5, 4};
        System.out.println("Prices: 3 1 2 5 4");
        System.out.println("Brute force O(n²): " + bruteForce(prices) + " inversions");
        System.out.println("Merge sort O(n log n): " + mergeSort(prices) + " inversions");
        System.out.println("Both agree: " + (bruteForce(prices) == mergeSort(prices)));
        System.out.println();
        System.out.println("Interview explanation:");
        System.out.println("  O(n²): two nested loops — works for small n, unusable for n=1M");
        System.out.println("  O(n log n): use merge sort — during merge, count inversions");
        System.out.println("  Key insight: sorted subarrays let us count ALL inversions in O(1)");
    }
}

