    // O(n²): artificially bad — double loop but stops early (demo only)
    static boolean solutionN2(int[] sorted, int target) {
        for (int i = 0; i < sorted.length; i++)
            for (int j = 0; j <= i; j++)
                if (sorted[j] == target) return true;
        return false;
    }

    // O(n): linear scan
    static boolean solutionN(int[] sorted, int target) {
        for (int x : sorted) { if (x == target) return true; if (x > target) return false; }
        return false;
    }

    // O(log n): binary search ← optimal for sorted array
    static boolean solutionLogN(int[] sorted, int target) {
        int lo = 0, hi = sorted.length - 1;
        while (lo <= hi) {
            int mid = lo + (hi - lo) / 2;
            if (sorted[mid] == target) return true;
            else if (sorted[mid] < target) lo = mid + 1;
            else hi = mid - 1;
        }
        return false;
    }

    // O(1): for specific case (check first/last only if we know range)
    static boolean solutionO1(int[] sorted, int target) {
        if (sorted.length == 0) return false;
        return sorted[0] == target || sorted[sorted.length-1] == target; // only checks ends
        // Note: this only works for specific targets; shown for O(1) demo
    }

    static String classify(int n, long ops) {
        if (ops <= 1) return "O(1)";
        long logN = (long)(Math.log(n) / Math.log(2)) + 1;
        if (ops <= logN * 2) return "O(log n)";
        if (ops <= n * 2) return "O(n)";
        if (ops <= n * logN * 2) return "O(n log n)";
        if (ops <= (long)n * n * 2) return "O(n²)";
        return "O(2ⁿ) or worse";
    }

    public static void main(String[] args) {
        int n = 100_000;
        int[] sorted = new int[n];
        for (int i = 0; i < n; i++) sorted[i] = i * 2; // even numbers 0,2,4,...
        int target = 99_999; // odd — not in array (worst case)

        long s, t;
        System.out.printf("%-15s %-10s %-10s%n", "Algorithm", "Time(ms)", "Result");
        System.out.println("-".repeat(35));

        s = System.currentTimeMillis(); solutionN2(sorted, target); t = System.currentTimeMillis()-s;
        System.out.printf("%-15s %-10d %-10s%n", "O(n²)", t, "false");

        s = System.currentTimeMillis(); solutionN(sorted, target); t = System.currentTimeMillis()-s;
        System.out.printf("%-15s %-10d %-10s%n", "O(n)", t, "false");

        s = System.currentTimeMillis(); boolean r = solutionLogN(sorted, target); t = System.currentTimeMillis()-s;
        System.out.printf("%-15s %-10d %-10s%n", "O(log n)", t, r);

        System.out.println();
        System.out.println("classify(" + n + ", 17) = " + classify(n, 17)); // ~log n
        System.out.println("classify(" + n + ", " + n + ") = " + classify(n, n)); // n
        System.out.println("classify(" + n + ", " + ((long)n*n) + ") = " + classify(n, (long)n*n)); // n²
        System.out.println();
        System.out.println("Big-O synthesis complete: O(log n) optimal for sorted search");
    }
}
